import{c as l,a7 as i,y as n,v as t,D as a,B as h}from"./chunks/framework.3cjvm90C.js";const p=JSON.parse('{"title":"Multi-Head Latent Attention (MLA)","description":"详解 DeepSeek 提出的多头潜在注意力机制 MLA 的数学推导与低秩压缩原理","frontmatter":{"title":"Multi-Head Latent Attention (MLA)","description":"详解 DeepSeek 提出的多头潜在注意力机制 MLA 的数学推导与低秩压缩原理"},"headers":[],"relativePath":"aigc/pretrain/mla.md","filePath":"aigc/pretrain/mla.md","lastUpdated":1782447613000}'),r={name:"aigc/pretrain/mla.md"};function m(b,e,d,o,$,s){return i(),n("div",null,[...e[0]||(e[0]=[t("h1",{id:"multi-head-latent-attention-mla",tabindex:"-1"},[a("Multi-Head Latent Attention (MLA) "),t("a",{class:"header-anchor",href:"#multi-head-latent-attention-mla","aria-label":"Permalink to “Multi-Head Latent Attention (MLA)”"},"​")],-1),t("p",null,"Multi-Head Latent Attention（MLA）是 DeepSeek 提出的一种高效注意力机制，通过对 KV 缓存进行低秩联合压缩，在显著降低推理阶段显存占用的同时，保持与标准多头注意力（MHA）相当的模型性能。其核心思想是将键（Key）和值（Value）投影到低维潜在空间，仅缓存压缩后的隐向量，并在计算时通过上投影恢复。以下是 MLA 的详细数学推导。",-1),t("blockquote",null,[t("p",null,[t("strong",null,"约定"),a("：所有计算使用行向量，即 $y = xW$。")])],-1),t("h2",{id:"q-的计算",tabindex:"-1"},[a("Q 的计算 "),t("a",{class:"header-anchor",href:"#q-的计算","aria-label":"Permalink to “Q 的计算”"},"​")],-1),t("p",null,[a("$$ \\begin{align} \\mathbf{c}"),t("em",{t:""},"{t}^{Q} &= \\mathbf{h}"),a(" W^{DQ}, \\ [\\mathbf{q}"),t("em",{"t,":"",2:""},"{t, 1}^{C};\\mathbf{q}"),a("^{C};...;\\mathbf{q}"),t("em",null,"{t, n"),a("{h}}^{C}] = \\mathbf{q}"),t("em",{t:""},"{t}^{C} &= \\mathbf{c}"),a("^{Q} W^{UQ}, \\ [\\mathbf{q}"),t("em",{"t,":"",2:""},"{t, 1}^{R};\\mathbf{q}"),a("^{R};...;\\mathbf{q}"),t("em",null,"{t, n"),a("{h}}^{R}] = \\mathbf{q}"),t("em",{t:""},"{t}^{R} &= \\operatorname{RoPE}(\\mathbf{c}"),a("^{Q} {W^{QR}}), \\ \\mathbf{q}"),t("em",{"t,":"",i:""},"{t, i} &= [\\mathbf{q}"),a("^{C}; \\mathbf{q}_{t, i}^{R}], \\end{align} $$")],-1),t("p",null,"其中：",-1),t("ul",null,[t("li",null,"$\\mathbf{c}_{t}^{Q} \\in \\mathbb{R}^{d_c^{\\prime}}$ 是查询的压缩隐向量；"),t("li",null,"$d_c^{\\prime} (\\ll d_h n_h)$ 表示查询压缩维度；"),t("li",null,"$W^{DQ} \\in \\mathbb{R}^{d \\times d_c^{\\prime}}$、$W^{UQ} \\in \\mathbb{R}^{d_c^{\\prime} \\times d_h n_h}$ 分别是查询的下投影和上投影矩阵；"),t("li",null,"$W^{QR} \\in \\mathbb{R}^{d_c^{\\prime} \\times d_h^R n_h}$ 用于生成携带 RoPE 的解耦查询。")],-1),t("h2",{id:"kv-的计算",tabindex:"-1"},[a("KV 的计算 "),t("a",{class:"header-anchor",href:"#kv-的计算","aria-label":"Permalink to “KV 的计算”"},"​")],-1),t("p",null,[a("$$ \\begin{align} \\boxed{\\color{blue} \\mathbf{c}"),t("em",{t:""},"{t}^{KV}} &= \\mathbf{h}"),a(" W^{DKV}, \\ [\\mathbf{k}"),t("em",{"t,":"",2:""},"{t, 1}^{C};\\mathbf{k}"),a("^{C};...;\\mathbf{k}"),t("em",null,"{t, n"),a("{h}}^{C}] = \\mathbf{k}"),t("em",{t:""},"{t}^{C} &= \\mathbf{c}"),a("^{KV} W^{UK}, \\ \\boxed{\\color{blue}\\mathbf{k}"),t("em",{t:""},"{t}^{R}} &= \\operatorname{RoPE}(\\mathbf{h}"),a(" {W^{KR}}), \\ \\mathbf{k}"),t("em",{"t,":"",i:""},"{t, i} &= [\\mathbf{k}"),a("^{C}; \\mathbf{k}"),t("em",{"t,":"",1:""},"{t}^{R}], \\ [\\mathbf{v}"),a("^{C};\\mathbf{v}"),t("em",null,"{t, 2}^{C};...;\\mathbf{v}"),a("{t, n_{h}}^{C}] = \\mathbf{v}"),t("em",{t:""},"{t}^{C} &= \\mathbf{c}"),a("^{KV} W^{UV}, \\end{align} $$")],-1),t("p",null,"其中：",-1),t("ul",null,[t("li",null,"$\\mathbf{c}_{t}^{KV} \\in \\mathbb{R}^{d_c}$ 是键值的压缩隐向量；"),t("li",null,"$d_c (\\ll d_h n_h)$ 表示 KV 压缩维度；"),t("li",null,"$W^{DKV} \\in \\mathbb{R}^{d \\times d_c}$ 是下投影矩阵；"),t("li",null,"$W^{UK}, W^{UV} \\in \\mathbb{R}^{d_c \\times d_h n_h}$ 是键和值的上投影矩阵；"),t("li",null,"$W^{KR} \\in \\mathbb{R}^{d \\times d_h^R}$ 用于生成携带 RoPE 的解耦键；"),t("li",null,"$\\operatorname{RoPE}(\\cdot)$ 表示应用旋转位置编码的操作。")],-1),t("blockquote",null,[t("p",null,[t("strong",null,"注意"),a("：对于 MLA，仅需缓存蓝色框中的向量（$\\color{blue} \\mathbf{c}"),t("em",{t:""},"{t}^{KV}$ 和 $\\color{blue}\\mathbf{k}"),a("^{R}$），从而显著减少 KV 缓存大小，同时保持与标准多头注意力（MHA）相当的性能。")])],-1),t("p",null,[a("最终，注意力查询（$\\mathbf{q}"),t("em",{"j,":"",i:""},"{t, i}$）、键（$\\mathbf{k}"),a("$）和值（$\\mathbf{v}"),t("em",{t:""},"{j, i}^{C}$）组合得到最终输出 $\\mathbf{u}"),a("$：")],-1),t("p",null,[a("$$ \\begin{align} \\mathbf{o}"),t("em",{j:"1"},"{t, i} &= \\sum"),a("^{t} \\operatorname{Softmax}"),t("em",{"t,":"",i:""},"j\\left(\\frac{\\mathbf{q}"),a(" \\mathbf{k}^T_{j, i}}{\\sqrt{d_{h} + d_{h}^{R}}}\\right) \\mathbf{v}"),t("em",{t:""},"{j, i}^{C}, \\ \\mathbf{u}"),a(" &= [\\mathbf{o}"),t("em",{"t,":"",2:""},"{t, 1};\\mathbf{o}"),a(";...;\\mathbf{o}"),t("em",null,"{t, n"),a("{h}}] W^{O}, \\end{align} $$")],-1),h('<p>其中 $W^{O} \\in \\mathbb{R}^{d_h n_h \\times d}$ 是输出投影矩阵。</p><h2 id="实际参数配置" tabindex="-1">实际参数配置 <a class="header-anchor" href="#实际参数配置" aria-label="Permalink to “实际参数配置”">​</a></h2><ul><li><p>$d = \\text{hidden_size} = 7168$</p></li><li><p>$d_c = \\text{kv_lora_rank} = 512$</p></li><li><p>$d_c^{\\prime} = \\text{q_lora_rank} = 1536$</p></li><li><p>$n_h = \\text{num_heads} = 128$</p></li><li><p>$d_h = \\text{qk_nope_head_dim} = 128$</p></li><li><p>$d_h^R = \\text{qk_rope_head_dim} = 64$</p></li><li><p>$W^{UQ}$ 和 $W^{QR}$ 可合并，$q_head_dim = qk_nope_head_dim + qk_rope_head_dim = 192$。</p></li><li><p>$W^{DKV}$ 和 $W^{KR}$ 可合并，$kv_lora_rank + qk_rope_head_dim = 576$。</p></li></ul><h2 id="矩阵吸收-absorb" tabindex="-1">矩阵吸收（Absorb） <a class="header-anchor" href="#矩阵吸收-absorb" aria-label="Permalink to “矩阵吸收（Absorb）”">​</a></h2><p>考虑如下计算：</p><p>$$ Y = X A B, \\quad C = A B $$</p><p>其中：</p><ul><li>$X \\in \\mathbb{R}^{m \\times d}$ 是输入隐状态（hidden states），</li><li>$A \\in \\mathbb{R}^{d \\times d_c}$、$B \\in \\mathbb{R}^{d_c \\times n}$ 是权重矩阵，</li><li>$C \\in \\mathbb{R}^{d \\times n}$ 是 absorb 后的等效权重矩阵。</li></ul><p>直接计算的 FLOPs 为： $$ 2 m d d_c + 2 m n d_c = 2 m d_c (d + n) $$</p><p>合并权重后计算的 FLOPs 为：$2 m d n$</p><p>当 $d_c$ 较小时，通常有： $$ \\boxed{d n &gt; d_c (d + n)} $$ 因此<strong>不一定需要合并两个权重矩阵</strong>！</p><p>不考虑 RoPE 部分，仅从 $\\mathbf{c}^Q$ 和 $\\mathbf{c}^{KV}$ 计算 $\\mathbf{q}_i \\mathbf{k}_i^T$（第 $i$ 个 head）：</p><p>$$ \\begin{align*} q_i k_i^T &amp;= \\boxed{\\mathbf{c}^{Q} W^{UQ}_i} ; \\boxed{(\\mathbf{c}^{KV} W^{UK}_i)^T}, \\ &amp;= \\boxed{\\mathbf{c}^{Q} W^{UQ}_i (W^{UK}_i)^T} (\\mathbf{c}^{KV})^T, \\ &amp;= \\boxed{q_i (W^{UK}_i)^T} (\\mathbf{c}^{KV})^T, &amp; \\text{(Absorb)} \\ &amp;= q_i \\boxed{(\\mathbf{c}^{KV} W^{UK}_i)^T}, &amp; \\text{(Normal)} \\ \\end{align*} $$</p><blockquote><p>⚠️ <strong>警告</strong>：此处 “Absorb” 的真实含义是<strong>利用矩阵乘法结合律</strong>，优先将 $\\mathbf{q}$ 与 $W^{UK}$ 结合，并缓存压缩隐向量 $\\mathbf{c}^{KV}$。它<strong>并非合并权重矩阵</strong>，“Absorb” 这一命名具有一定误导性！</p></blockquote><h3 id="为什么计算时不把-w-uq-i-w-uk-i-t-合并" tabindex="-1">为什么计算时不把 $W^{UQ}_i (W^{UK}_i)^T$ 合并？ <a class="header-anchor" href="#为什么计算时不把-w-uq-i-w-uk-i-t-合并" aria-label="Permalink to “为什么计算时不把 $W^{UQ}_i (W^{UK}_i)^T$ 合并？”">​</a></h3><p>对单个 token、单个 head，FLOPs 分别为：</p><ul><li>分开计算：$2 d_h (d_c^{\\prime} + d_c) = 524288$</li><li>合并计算：$2 d_c^{\\prime} d_c = 1572864 = 3 \\times 524288$</li></ul><p><strong>合并后计算量反而是原来的 3 倍！</strong></p><h3 id="为什么-prefill-阶段显式计算-k-和-v-而-decode-阶段不需要" tabindex="-1">为什么 Prefill 阶段显式计算 k 和 v，而 Decode 阶段不需要？ <a class="header-anchor" href="#为什么-prefill-阶段显式计算-k-和-v-而-decode-阶段不需要" aria-label="Permalink to “为什么 Prefill 阶段显式计算 k 和 v，而 Decode 阶段不需要？”">​</a></h3><p>假设输入 shape 如下：</p><ul><li>$\\mathbf{q} : (b, n_h, s_q, d_h)$</li><li>$\\mathbf{c}^{KV} : (b, 1, s_{kv}, d_c)$</li><li>$W^{UK} : (d_c, n_h d_h)$</li></ul><h4 id="prefill-阶段-s-q-s-kv-s" tabindex="-1"><strong>Prefill 阶段</strong>（$s_q = s_{kv} = s$） <a class="header-anchor" href="#prefill-阶段-s-q-s-kv-s" aria-label="Permalink to “Prefill 阶段（$s_q = s_{kv} = s$）”">​</a></h4><p>FLOPs 对比： $$ \\begin{align*} T_{\\text{Normal}} &amp;= 2 b n_h d_h s (d_c + s), \\ T_{\\text{Absorb}} &amp;= 2 b n_h d_c s (d_h + s), \\ \\frac{T_{\\text{Normal}}}{T_{\\text{Absorb}}} &amp;= \\frac{d_h (d_c + s)}{d_c (d_h + s)} = \\frac{s + 512}{4s + 512} \\in \\left( \\frac{1}{4}, 1 \\right) \\end{align*} $$</p><p>→ <strong>Prefill 阶段 Normal 更快</strong>，且此阶段是<strong>计算瓶颈</strong>，故显式计算 $\\mathbf{q}$ 和 $\\mathbf{k}$。</p><h4 id="decode-阶段-s-q-1-s-kv-s" tabindex="-1"><strong>Decode 阶段</strong>（$s_q = 1, s_{kv} = s$） <a class="header-anchor" href="#decode-阶段-s-q-1-s-kv-s" aria-label="Permalink to “Decode 阶段（$s_q = 1, s_{kv} = s$）”">​</a></h4><p>FLOPs 对比： $$ \\begin{align*} T_{\\text{Normal}}^{K} &amp;= 2 b n_h d_h (d_c + s), &amp; \\text{(缓存 k)} \\ T_{\\text{Normal}}^{L} &amp;= 2 b n_h d_h (d_c s + s), &amp; \\text{(缓存 latent)} \\ T_{\\text{Absorb}} &amp;= 2 b n_h d_c (d_h + s), \\ \\frac{T_{\\text{Normal}}^{K}}{T_{\\text{Absorb}}} &amp;= \\frac{d_h (d_c + s)}{d_c (d_h + s)} = \\frac{s + 512}{4s + 512} \\in (0.25, 1) \\ \\frac{T_{\\text{Normal}}^{L}}{T_{\\text{Absorb}}} &amp;= \\frac{513 s}{4s + 512} \\in (0.99, 128.25) \\end{align*} $$</p><p>虽然缓存 k 的计算量最小（极限为 Absorb 的 1/4），但 <strong>Decode 阶段瓶颈是显存带宽</strong>。</p><h5 id="内存读取量对比-bfloat16-精度" tabindex="-1">内存读取量对比（bfloat16 精度）： <a class="header-anchor" href="#内存读取量对比-bfloat16-精度" aria-label="Permalink to “内存读取量对比（bfloat16 精度）：”">​</a></h5><ul><li><p><strong>MLA (Absorb)</strong>：$(b, n_h, 1, d_c) \\times (b, 1, s, d_c)$ $$ M_{\\text{MLA}} = 2 b d_c (n_h + s) $$</p></li><li><p><strong>标准 MHA</strong>：$(b, n_h, 1, d_h) \\times (b, n_h, s, d_h)$ $$ M_{\\text{MHA}} = 2 b d_h n_h (1 + s) $$</p></li></ul><p>内存读取比例： $$ \\frac{M_{\\text{MLA}}}{M_{\\text{MHA}}} = \\frac{d_c (n_h + s)}{d_h n_h (1 + s)} = \\frac{128 + s}{32 (1 + s)} $$</p><ul><li>当 $s = 20$，比值 ≈ 0.22；</li><li>极限情况（$s \\to \\infty$）：比值 → $1/32$。</li></ul><p>✅ 因此，<strong>Decode 阶段采用 Absorb 方式</strong>，可大幅降低显存带宽压力，并<strong>复用 MQA（Multi-Query Attention）实现</strong>。</p><h2 id="矩阵吸收问题总结" tabindex="-1">矩阵吸收问题总结 <a class="header-anchor" href="#矩阵吸收问题总结" aria-label="Permalink to “矩阵吸收问题总结”">​</a></h2><p>“矩阵吸收”的本质是<strong>如何应用矩阵乘法结合律</strong>：</p><p>$$ \\begin{align*} Y &amp;= (X A) B = X (A B), \\ Z &amp;= (X W) Y = X (W Y), \\end{align*} $$</p><p>其中 $A, B, W$ 均为权重矩阵。</p><p><strong>决策依据</strong>应综合权衡：</p><ul><li>计算量（FLOPs）</li><li>显存读写量（Memory Traffic）</li><li>当前阶段瓶颈（计算 or 带宽）</li></ul><p>可借助 <strong>Roofline Model</strong> 进行系统性分析。</p>',39)])])}const c=l(r,[["render",m]]);export{p as __pageData,c as default};
